    #[cfg(not(feature = "shielded-groth16-verifier"))]
    #[derive(Debug)]
    struct AcceptingGroth16TestAdapter;

    #[cfg(not(feature = "shielded-groth16-verifier"))]
    impl Groth16VerifierAdapter for AcceptingGroth16TestAdapter {
        fn verify(
            &self,
            _verifying_key_bytes: &[u8],
            _public_inputs: &ShieldedPublicInputs,
            _canonical_public_inputs: &[u8],
            _canonical_public_input_words: &[[u8; 32]],
            payload: &ParsedGroth16ProofPayload,
        ) -> Result<(), misaka_shielded::ProofError> {
            if payload.proof_bytes.is_empty() {
                return Err(misaka_shielded::ProofError::Malformed(
                    "empty Groth16 shell payload".to_string(),
                ));
            }
            Ok(())
        }
    }

    #[cfg(not(feature = "shielded-groth16-verifier"))]
    fn groth16_test_vk_bytes() -> Vec<u8> {
        vec![0x91, 0xA2, 0xB3, 0xC4]
    }

    #[cfg(not(feature = "shielded-groth16-verifier"))]
    fn compute_test_vk_fingerprint(verifying_key_bytes: &[u8]) -> [u8; 32] {
        let mut hasher = blake3::Hasher::new_derive_key("MISAKA shielded vk fingerprint v1");
        hasher.update(verifying_key_bytes);
        *hasher.finalize().as_bytes()
    }

    #[cfg(not(feature = "shielded-groth16-verifier"))]
    fn compute_test_public_input_hash(public_inputs: &ShieldedPublicInputs) -> [u8; 32] {
        let canonical_inputs = public_inputs
            .canonical_bytes_v1()
            .expect("canonical public inputs");
        let mut hasher = blake3::Hasher::new_derive_key("MISAKA shielded public input hash v1");
        hasher.update(&canonical_inputs);
        *hasher.finalize().as_bytes()
    }

    #[cfg(not(feature = "shielded-groth16-verifier"))]
    fn build_test_groth16_shell_proof(
        verifying_key_bytes: &[u8],
        public_inputs: &ShieldedPublicInputs,
        payload: &[u8],
    ) -> ShieldedProof {
        let fingerprint = compute_test_vk_fingerprint(verifying_key_bytes);
        let public_input_hash = compute_test_public_input_hash(public_inputs);
        let mut bytes = Vec::with_capacity(4 + 1 + 1 + 32 + 32 + payload.len());
        bytes.extend_from_slice(b"MSKP");
        bytes.push(1);
        bytes.push(1);
        bytes.extend_from_slice(&fingerprint);
        bytes.extend_from_slice(&public_input_hash);
        bytes.extend_from_slice(payload);
        ShieldedProof { bytes }
    }

