    fn make_deposit_with_commitment(
        output_commitment: NoteCommitment,
        note_byte: u8,
        amount: u64,
    ) -> ShieldDepositTx {
        use sha3::{Digest, Sha3_256};

        let kp = MlDsaKeypair::generate();
        let pubkey_bytes = kp.public_key.as_bytes().to_vec();

        let mut h = Sha3_256::new();
        h.update(b"MISAKA:address:v1:");
        h.update(&pubkey_bytes);
        let hash = h.finalize();
        let mut from = [0u8; 32];
        from.copy_from_slice(&hash);

        let mut tx = ShieldDepositTx {
            from,
            amount,
            asset_id: 0,
            fee: MIN_SHIELDED_FEE,
            output_commitment,
            encrypted_note: EncryptedNote {
                epk: [note_byte; 32],
                ciphertext: vec![note_byte; 64],
                tag: [0u8; 16],
                view_tag: 0,
            },
            signature_bytes: vec![],
            sender_pubkey: pubkey_bytes,
        };

        let payload = tx.signing_payload();
        let sig = misaka_pqc::ml_dsa_sign(&kp.secret_key, &payload).expect("sign ok");
        tx.signature_bytes = sig.as_bytes().to_vec();
        tx
    }

    fn make_real_sha3_transfer_fixture_with_seed(
        shared: &SharedShieldedState,
        seed: u8,
    ) -> ShieldedTransferTx {
        let mut state = shared.write();

        let input_value = 10_000_000u64;
        let output_value = input_value - MIN_SHIELDED_FEE;
        let nk_commit = [0x71u8.wrapping_add(seed); 32];
        let input_rcm = [0x52u8.wrapping_add(seed); 32];
        let output_rcm = [0x99u8.wrapping_add(seed); 32];
        let recipient_pk = [0x55u8.wrapping_add(seed); 32];

        let input_commitment = NoteCommitment(Sha3TransferProofBackend::compute_commitment(
            input_value,
            0,
            &nk_commit,
            &input_rcm,
        ));
        let deposit_tx = make_deposit_with_commitment(
            input_commitment,
            0xD4u8.wrapping_add(seed),
            input_value,
        );
        let (_, deposit_receipt) = state
            .apply_deposit(
                &deposit_tx,
                [0x11u8.wrapping_add(seed); 32],
                100 + seed as u64,
            )
            .expect("deposit ok");

        let witness = state
            .merkle_witness(deposit_receipt.positions[0])
            .expect("witness");
        let mut builder = Sha3TransferProofBuilder::new(MIN_SHIELDED_FEE);
        builder.add_input(ProofInput {
            position: witness.position as u32,
            merkle_siblings: witness.auth_path,
            value: input_value,
            asset_id: 0,
            rcm: input_rcm,
            nk_commit,
        });
        builder.add_output(ProofOutput {
            value: output_value,
            asset_id: 0,
            recipient_pk,
            rcm: output_rcm,
        });
        let (proof, nullifiers, commitments) = builder.build().expect("proof build");

        ShieldedTransferTx {
            nullifiers,
            output_commitments: commitments,
            anchor: deposit_receipt.new_root,
            fee: MIN_SHIELDED_FEE,
            encrypted_outputs: vec![EncryptedNote {
                epk: [0x22u8.wrapping_add(seed); 32],
                ciphertext: vec![0x44u8.wrapping_add(seed); 64],
                tag: [0u8; 16],
                view_tag: 0,
            }],
            proof,
            circuit_version: CircuitVersion::SHA3_TRANSFER_V2,
            public_memo: Some(format!("dag rpc confirmed shielded {}", seed).into_bytes()),
        }
    }

    fn make_real_sha3_transfer_fixture(shared: &SharedShieldedState) -> ShieldedTransferTx {
        make_real_sha3_transfer_fixture_with_seed(shared, 0)
    }

