    fn unique_temp_dir(label: &str) -> String {
        let unique = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .expect("time")
            .as_nanos();
        let path = std::env::temp_dir().join(format!("{}-{}", label, unique));
        std::fs::create_dir_all(&path).expect("dir");
        path.to_string_lossy().into_owned()
    }

    fn maybe_write_shielded_bounded_e2e_result(payload: &serde_json::Value) {
        let Ok(path) = std::env::var("MISAKA_SHIELDED_BOUNDED_E2E_RESULT") else {
            return;
        };
        let path = std::path::PathBuf::from(path);
        if let Some(parent) = path.parent() {
            std::fs::create_dir_all(parent).expect("create result dir");
        }
        std::fs::write(
            &path,
            serde_json::to_string_pretty(payload).expect("bounded e2e json"),
        )
        .expect("write bounded e2e result");
    }

