                entry["txResults"]
                    .as_array()
                    .into_iter()
                    .flatten()
                    .filter_map(|result| {
                        let tx_hash = result["txHash"].as_str()?;
                        let accepted = result["accepted"].as_bool().unwrap_or(false);
                        if accepted
                            && (tx_hash == first_tx_hash_hex.as_str()
                                || tx_hash == second_tx_hash_hex.as_str())
                        {
                            Some(tx_hash.to_string())
                        } else {
                            None
                        }
                    })
